export const TASK_STATUS={PENDING:1,DOING:2,COMPLETED:3,CANCELLED:4};const STATE_CONFIG={[TASK_STATUS.PENDING]:{label:"MỚI",color:"bg-blue-500 text-white",actions:["START","DONE","CANCEL"]},[TASK_STATUS.DOING]:{label:"ĐANG LÀM",color:"bg-indigo-500 text-white animate-pulse",actions:["DONE","CANCEL"]},[TASK_STATUS.COMPLETED]:{label:"HOÀN THÀNH",color:"bg-emerald-500 text-white",actions:["REDO"]},[TASK_STATUS.CANCELLED]:{label:"ĐÃ HỦY",color:"bg-slate-400 text-white line-through",actions:["REDO"]}},ACTION_CONFIG={START:{target:2,icon:"play",class:"bg-indigo-50 text-indigo-600"},DONE:{target:3,icon:"check",class:"bg-emerald-50 text-emerald-600"},CANCEL:{target:4,icon:"x",class:"bg-rose-50 text-rose-500"},REDO:{target:1,icon:"rotate-ccw",class:"bg-amber-50 text-amber-600"}};export const TaskStateMachine={getStateInfo:t=>STATE_CONFIG[t]||STATE_CONFIG[1],getAvailableActions(t){const e=this.getStateInfo(t);return e&&e.actions?e.actions.map((t=>({key:t,...ACTION_CONFIG[t]}))):[]}};